function toggleContrast(classContrast) { document.body.classList.toggle(classContrast); } function setContrast() { let status_btn_contrast = document.getElementById("checkSwitch").checked; localStorage.setItem("status_contrast", status_btn_contrast); } function getContrast() { let status_contrast_localStorage = localStorage.getItem("status_contrast"); if (status_contrast_localStorage == "true") { document.getElementById("checkSwitch").checked = true; toggleContrast("dark"); } else { setContrast(); } } function handleClickFocus(event) { event.preventDefault(); const targetId = this.getAttribute("href"); const targetElement = document.querySelector(targetId); if (targetElement) { targetElement.tabIndex = -1; targetElement.focus(); targetElement.removeAttribute("tabindex"); } } function ocultarIconosInaccesibles() { let iconos = document.querySelectorAll('.mb2mm-arrow, [class^="fab fa-"]'); if (iconos.length === 0) { console.warn("No se encontraron iconos para ocultar."); return; } iconos.forEach(function (icono) { icono.setAttribute("aria-hidden", "true"); }); } function agregarSpanEnlacesExternos() { let enlacesExternos = document.querySelectorAll(".link-new-window"); if (enlacesExternos.length === 0) { console.warn('No se encontraron enlaces con la clase .link-new-window".'); return; } enlacesExternos.forEach(function (enlace) { let span = document.createElement("span"); span.textContent = "(Abre en una nueva ventana)"; span.classList.add("sr-only"); enlace.appendChild(span); }); } document.addEventListener("DOMContentLoaded", () => { const status_btn_contrast = document.getElementById("checkSwitch"); status_btn_contrast.addEventListener("click", setContrast); getContrast(); ocultarIconosInaccesibles(); agregarSpanEnlacesExternos(); const menuLinks = document.querySelectorAll(".navbar-nav .nav-link"); menuLinks.forEach((link) => { link.addEventListener("click", handleClickFocus); }); });
